def is_palindrome(s):
    t = ''.join(c.lower() for c in s if not c.isspace())
    return t == t[::-1]

def is_anagram(a,b):
    norm = lambda s: sorted(c.lower() for c in s if not c.isspace())
    return norm(a) == norm(b)

def most_common_char(s):
    from collections import Counter
    c = Counter(s)
    return max(c, key=lambda k:(c[k], -list(c).index(k)))

def compress(s):
    if not s: return ''
    out, prev, cnt = [], s[0], 0
    for c in s:
        if c == prev: cnt += 1
        else:
            out.append(f'{prev}{cnt}'); prev=c; cnt=1
    out.append(f'{prev}{cnt}')
    return ''.join(out)

def second_largest(nums):
    u = sorted(set(nums), reverse=True)
    return u[1] if len(u)>=2 else None

def unique(xs):
    seen=set(); out=[]
    for x in xs:
        if x not in seen: seen.add(x); out.append(x)
    return out

def running_max(nums):
    out=[]; m=float('-inf')
    for n in nums:
        m=max(m,n); out.append(m)
    return out

def spiral(m):
    res=[]; m=[row[:] for row in m]
    while m:
        res += m.pop(0)
        if m and m[0]:
            for r in m: res.append(r.pop())
        if m:
            res += m.pop()[::-1]
        if m and m[0]:
            for r in reversed(m): res.append(r.pop(0))
    return res

def word_freq(s):
    from collections import Counter
    return dict(Counter(s.lower().split()))

def group_by_len(words):
    from collections import defaultdict
    d=defaultdict(list)
    for w in words: d[len(w)].append(w)
    return {k:sorted(v) for k,v in d.items()}

def two_sum(nums,target):
    seen={}
    for j,n in enumerate(nums):
        if target-n in seen: return (seen[target-n], j)
        seen[n]=j
    return None

def first_unique(s):
    from collections import Counter
    c=Counter(s)
    for ch in s:
        if c[ch]==1: return ch
    return ''

def dense_rank(scores):
    uniq=sorted(set(scores), reverse=True)
    pos={v:i+1 for i,v in enumerate(uniq)}
    return [pos[s] for s in scores]

def fb(n):
    out=[]
    for i in range(1,n+1):
        if i%15==0: out.append('FizzBuzz')
        elif i%3==0: out.append('Fizz')
        elif i%5==0: out.append('Buzz')
        else: out.append(str(i))
    return out

def countdown(start, step):
    out=[]; n=start
    while n>=0:
        out.append(n); n-=step
    return out

def rsum(xs):
    if not xs: return 0
    return xs[0] + rsum(xs[1:])

def deep_flatten(xs):
    out=[]
    for x in xs:
        if isinstance(x,list): out.extend(deep_flatten(x))
        else: out.append(x)
    return out

def power(x, n):
    if n==0: return 1
    half=power(x, n//2)
    return half*half*(x if n%2 else 1)

def balanced(s):
    pairs={')':'(',']':'[','}':'{'}
    st=[]
    for c in s:
        if c in '([{': st.append(c)
        elif c in pairs:
            if not st or st.pop()!=pairs[c]: return False
    return not st

def shortest_len(g, start, end):
    from collections import deque
    if start==end: return 0
    seen={start}; q=deque([(start,0)])
    while q:
        node,d=q.popleft()
        for nb in g.get(node,[]):
            if nb==end: return d+1
            if nb not in seen:
                seen.add(nb); q.append((nb,d+1))
    return -1

def reverse_ll(xs):
    prev=None
    for x in xs:
        prev=(x,prev)
    out=[]
    while prev:
        out.append(prev[0]); prev=prev[1]
    return out

def k_smallest(nums,k):
    import heapq
    return sorted(heapq.nsmallest(k,nums))

def apply(ops):
    st=[]; mins=[]; out=[]
    for op in ops:
        if op[0]=='push':
            v=op[1]; st.append(v)
            mins.append(v if not mins else min(v,mins[-1]))
        elif op[0]=='pop':
            st.pop(); mins.pop()
        else:
            out.append(mins[-1])
    return out

def pair_sum(arr, target):
    i,j=0,len(arr)-1
    while i<j:
        s=arr[i]+arr[j]
        if s==target: return (i,j)
        if s<target: i+=1
        else: j-=1
    return None

def max_avg(arr,k):
    cur=sum(arr[:k]); best=cur
    for i in range(k,len(arr)):
        cur += arr[i]-arr[i-k]
        if cur>best: best=cur
    return best/k

def components(g):
    seen=set(); n=0
    def dfs(u):
        st=[u]
        while st:
            x=st.pop()
            for nb in g.get(x,[]):
                if nb not in seen:
                    seen.add(nb); st.append(nb)
    for v in g:
        if v not in seen:
            seen.add(v); dfs(v); n+=1
    return n

def merge_intervals(ivs):
    ivs=sorted(ivs)
    out=[]
    for s,e in ivs:
        if out and s<=out[-1][1]:
            out[-1][1]=max(out[-1][1],e)
        else:
            out.append([s,e])
    return out

def anagram_n(a,b):
    if len(a)!=len(b): return False
    from collections import Counter
    return Counter(a)==Counter(b)

def common(a,b):
    sb=set(b)
    for x in a:
        if x in sb: return True
    return False

def dedupe(records, key):
    seen=set(); out=[]
    for r in records:
        k=r[key]
        if k not in seen: seen.add(k); out.append(r)
    return out

def total_by_region(rows):
    out={}
    for r in rows: out[r['region']] = out.get(r['region'],0) + r['amount']
    return out

def clean(values):
    out=[]
    for v in values:
        if v is None: continue
        s=v.strip()
        if s: out.append(s)
    return out

def pivot(rows, metrics):
    by_date={}
    for r in rows:
        d=by_date.setdefault(r['date'], {'date':r['date']})
        d[r['metric']] = d.get(r['metric'],0) + r['value']
    out=[]
    for d in sorted(by_date):
        rec={'date':d}
        for m in metrics: rec[m] = by_date[d].get(m, 0)
        out.append(rec)
    return out
